def perceive(data):
    out = {}
    for line in str(data).splitlines():
        if ':' in line:
            k, v = line.split(':', 1)
            k = k.strip(); v = v.strip()
            if k in ('priority', 'load'):
                out[k] = int(v) if v.lstrip('-').isdigit() else 0
    return out
